import java.util.function.Predicate;

// Test whether a string is not empty
Predicate<String> isNotEmpty = s -> !s.isEmpty();
System.out.println(isNotEmpty.test("Hello"));  // true
System.out.println(isNotEmpty.test(""));        // false

// Test whether a number is positive
Predicate<Integer> isPositive = n -> n > 0;
System.out.println(isPositive.test(5));   // true
System.out.println(isPositive.test(-3));  // false

// Using a method reference
Predicate<String> isBlank = String::isBlank;
System.out.println(isBlank.test("  "));  // true

Predicate<String> hasA = s -> s.contains("A");
Predicate<String> lengthOver3 = s -> s.length() > 3;

// and(): both conditions must be satisfied
Predicate<String> combined = hasA.and(lengthOver3);
System.out.println(combined.test("ABCD"));  // true
System.out.println(combined.test("AB"));    // false (length too short)
System.out.println(combined.test("BCDE"));  // false (no A)

// or(): either condition must be satisfied
Predicate<String> either = hasA.or(lengthOver3);
System.out.println(either.test("A"));     // true
System.out.println(either.test("BCDE"));  // true

// negate(): negation of the condition
Predicate<String> noA = hasA.negate();
System.out.println(noA.test("BCD"));  // true
System.out.println(noA.test("ABC"));  // false

Predicate<String> isHello = Predicate.isEqual("Hello");
System.out.println(isHello.test("Hello"));  // true
System.out.println(isHello.test("World"));  // false
System.out.println(isHello.test(null));      // false

// Equality test with null
Predicate<String> isNull = Predicate.isEqual(null);
System.out.println(isNull.test(null));     // true
System.out.println(isNull.test("Hello"));  // false

// not() static method (Java 11+)
Predicate<String> notEmpty = Predicate.not(String::isEmpty);
System.out.println(notEmpty.test(""));      // false
System.out.println(notEmpty.test("Java"));  // true

List<String> names = new ArrayList<>(List.of("Alice", "Bob", "Anna", "Charlie"));

Predicate<String> startsWithA = s -> s.startsWith("A");

// Used with filter
names.stream()
     .filter(startsWithA)
     .forEach(System.out::println);  // Alice, Anna

// Used with removeIf
names.removeIf(startsWithA);
System.out.println(names);  // [Bob, Charlie]

// allMatch / anyMatch / noneMatch
List<Integer> nums = List.of(2, 4, 6, 8);
Predicate<Integer> isEven = n -> n % 2 == 0;
System.out.println(nums.stream().allMatch(isEven));   // true
System.out.println(nums.stream().anyMatch(isEven));   // true
System.out.println(nums.stream().noneMatch(isEven));  // false

