import java.util.function.Function;

// A function that returns the length of a string
Function<String, Integer> strLength = String::length;
System.out.println(strLength.apply("Hello"));  // 5
System.out.println(strLength.apply(""));       // 0

// A function that doubles an integer
Function<Integer, Integer> doubleIt = n -> n * 2;
System.out.println(doubleIt.apply(5));  // 10

// A function that converts a string to uppercase
Function<String, String> toUpper = String::toUpperCase;
System.out.println(toUpper.apply("java"));  // JAVA

Function<Integer, Integer> multiply2 = n -> n * 2;
Function<Integer, Integer> add3 = n -> n + 3;

// andThen: apply multiply2 first, then add3
// multiply2(5) → 10 → add3(10) → 13
Function<Integer, Integer> mulThenAdd = multiply2.andThen(add3);
System.out.println(mulThenAdd.apply(5));  // 13

// compose: apply add3 first, then multiply2
// add3(5) → 8 → multiply2(8) → 16
Function<Integer, Integer> addThenMul = multiply2.compose(add3);
System.out.println(addThenMul.apply(5));  // 16

// Composition with different types
Function<String, Integer> len = String::length;
Function<Integer, String> toStr = n -> "Length: " + n;
Function<String, String> lenMsg = len.andThen(toStr);
System.out.println(lenMsg.apply("Java"));  // Length: 4

import java.util.function.UnaryOperator;

// UnaryOperator: input and output are the same type
UnaryOperator<String> toUpper = String::toUpperCase;
System.out.println(toUpper.apply("hello"));  // HELLO

// Function.identity(): returns the argument as-is
Function<String, String> identity = Function.identity();
System.out.println(identity.apply("test"));  // test

// Usage with List.replaceAll()
List<String> list = new ArrayList<>(List.of("a", "b", "c"));
list.replaceAll(String::toUpperCase);
System.out.println(list);  // [A, B, C]

// Using identity with Stream.toMap()
List<String> words = List.of("apple", "banana", "cherry");
Map<Integer, String> map = words.stream()
    .collect(Collectors.toMap(String::length, Function.identity()));

// Example of a data transformation pipeline
Function<String, String> trim = String::trim;
Function<String, String> lower = String::toLowerCase;
Function<String, String> normalize = trim.andThen(lower);

System.out.println(normalize.apply("  HELLO  "));  // hello

// Using composition with Streams
List<String> data = List.of(" Java ", " Python ", " Go ");
data.stream()
    .map(normalize)
    .forEach(System.out::println);
// java
// python
// go

