import java.util.function.Consumer;

// A Consumer that prints output
Consumer<String> print = System.out::println;
print.accept("Hello");  // Hello

// A Consumer that converts to uppercase and prints
Consumer<String> shout = s -> System.out.println(s.toUpperCase());
shout.accept("hello");  // HELLO

// Chain with andThen()
Consumer<String> printThenShout = print.andThen(shout);
printThenShout.accept("java");
// java
// JAVA

// Used with forEach
List<String> list = List.of("A", "B", "C");
list.forEach(print);  // A B C (printed on each line)

import java.util.function.Supplier;

// A Supplier that provides a string
Supplier<String> greeting = () -> "Hello, World!";
System.out.println(greeting.get());  // Hello, World!

// Creating objects with a constructor reference
Supplier<List<String>> listFactory = ArrayList::new;
List<String> newList = listFactory.get();
newList.add("Java");
System.out.println(newList);  // [Java]

// Lazy evaluation with Optional
Optional<String> opt = Optional.empty();
String result = opt.orElseGet(() -> "default value");
System.out.println(result);  // default value

// Difference between orElse and orElseGet
// orElse(heavyCompute())     → heavyCompute() is always executed
// orElseGet(() -> heavyCompute()) → executed only when value is absent

// Usage with Stream.generate
Supplier<Double> randomSupplier = Math::random;
Stream.generate(randomSupplier)
      .limit(3)
      .forEach(System.out::println);
// 0.123... 0.456... 0.789... (random values)

// Leveraging Supplier with Objects.requireNonNull
String name = null;
try {
    Objects.requireNonNull(name, () -> "name is" + " null");
} catch (NullPointerException e) {
    System.out.println(e.getMessage());  // name is null
}

// Practical Consumer example: separating concerns
Consumer<String> log = s -> System.out.println("[LOG] " + s);
Consumer<String> save = s -> System.out.println("[SAVE] " + s);
Consumer<String> process = log.andThen(save);
process.accept("data");
// [LOG] data
// [SAVE] data

// Reference table of key functional interfaces
// Predicate<T>   : T → boolean  | test(T)      | filter, removeIf
// Function<T,R>  : T → R        | apply(T)     | map, Stream.toMap
// Consumer<T>    : T → void     | accept(T)    | forEach, peek
// Supplier<T>    : () → T       | get()         | orElseGet, generate
// UnaryOperator<T>  : T → T     | apply(T)     | replaceAll
// BinaryOperator<T> : (T,T) → T | apply(T,T)   | reduce, merge

