import java.util.function.BiFunction;
import java.util.function.BiPredicate;

// Generate a result from two arguments
BiFunction<String, Integer, String> repeat = (s, n) -> s.repeat(n);
System.out.println(repeat.apply("Ha", 3));  // HaHaHa

// Add a transformation with andThen
BiFunction<Integer, Integer, Integer> add = Integer::sum;
Function<Integer, String> toStr = n -> "Total: " + n;
BiFunction<Integer, Integer, String> addAndFormat = add.andThen(toStr);
System.out.println(addAndFormat.apply(3, 7));  // Total: 10

// BiPredicate: conditional test with two arguments
BiPredicate<String, Integer> lengthCheck = (s, n) -> s.length() > n;
System.out.println(lengthCheck.test("Java", 3));  // true
System.out.println(lengthCheck.test("Go", 3));    // false

import java.util.function.BiConsumer;

// BiConsumer: takes two arguments
BiConsumer<String, Integer> printEntry = 
    (key, value) -> System.out.println(key + "=" + value);

// Used with Map.forEach
Map<String, Integer> scores = Map.of("Alice", 90, "Bob", 85, "Charlie", 92);
scores.forEach(printEntry);
// Alice=90
// Bob=85
// Charlie=92

// Chaining with andThen()
BiConsumer<String, Integer> logger = 
    (k, v) -> System.out.println("[LOG] " + k + ":" + v);
BiConsumer<String, Integer> combined = printEntry.andThen(logger);
combined.accept("test", 100);
// test=100
// [LOG] test:100

import java.util.function.BinaryOperator;

// BinaryOperator: takes two arguments of the same type and returns the same type
BinaryOperator<Integer> add = Integer::sum;
System.out.println(add.apply(3, 5));  // 8

// Used with Stream.reduce
List<Integer> nums = List.of(1, 2, 3, 4, 5);
int sum = nums.stream().reduce(0, Integer::sum);
System.out.println(sum);  // 15

// minBy / maxBy
BinaryOperator<String> shorter = 
    BinaryOperator.minBy(Comparator.comparingInt(String::length));
System.out.println(shorter.apply("Java", "Go"));  // Go

BinaryOperator<String> longer = 
    BinaryOperator.maxBy(Comparator.comparingInt(String::length));
System.out.println(longer.apply("Java", "Go"));   // Java

// Used with Map.merge (sum values on collision)
Map<String, Integer> map = new HashMap<>();
map.put("A", 10);
map.merge("A", 5, Integer::sum);
System.out.println(map.get("A"));  // 15

// Comparing single-argument and Bi versions
Function<String, Integer> f1 = String::length;           // 1 argument
BiFunction<String, String, Integer> f2 =                 // 2 arguments
    (s1, s2) -> s1.length() + s2.length();

System.out.println(f1.apply("Java"));           // 4
System.out.println(f2.apply("Java", "Gold"));   // 8

// Currying for 3 arguments
Function<Integer, Function<Integer, Function<Integer, Integer>>> 
    addThree = a -> b -> c -> a + b + c;
System.out.println(addThree.apply(1).apply(2).apply(3));  // 6

// Multi-stage Function composition
Function<String, String> trim = String::trim;
Function<String, String> lower = String::toLowerCase;
Function<String, String> removeSpaces = s -> s.replace(" ", "");

// Pipeline: trim → lowercase → remove spaces
Function<String, String> normalize = 
    trim.andThen(lower).andThen(removeSpaces);

System.out.println(normalize.apply("  Hello World  "));
// helloworld

// Used with Streams (a single map suffices)
List<String> inputs = List.of(" Java ", " Python ", "  Go  ");
List<String> results = inputs.stream()
    .map(normalize)
    .collect(Collectors.toList());
System.out.println(results);  // [java, python, go]

// Predicate chain with compound conditions
Predicate<String> notEmpty = s -> !s.isEmpty();
Predicate<String> startsWithJ = s -> s.startsWith("J");
Predicate<String> lengthOver3 = s -> s.length() > 3;

// "Not empty" AND "starts with J" AND "length > 3"
Predicate<String> filter = notEmpty
    .and(startsWithJ)
    .and(lengthOver3);

List<String> langs = List.of("Java", "JavaScript", "Go", "Jython", "", "J");
langs.stream()
     .filter(filter)
     .forEach(System.out::println);
// Java
// JavaScript
// Jython

// Combining with or()
Predicate<String> startsWithP = s -> s.startsWith("P");
Predicate<String> jOrP = startsWithJ.or(startsWithP);

List.of("Java", "Python", "Go", "PHP").stream()
    .filter(jOrP)
    .forEach(System.out::println);
// Java
// Python
// PHP

// Example of a validation pipeline
Predicate<String> notNull = Objects::nonNull;
Predicate<String> notBlank = s -> !s.isBlank();
Predicate<String> validLength = s -> s.length() >= 3 && s.length() <= 20;
Predicate<String> alphaNumeric = s -> s.matches("[a-zA-Z0-9]+");

// Chain all conditions
Predicate<String> isValidUsername = notNull
    .and(notBlank)
    .and(validLength)
    .and(alphaNumeric);

// Transformation pipeline
Function<String, String> sanitize = 
    ((Function<String, String>) String::trim)
    .andThen(String::toLowerCase);

// Integrating validation and transformation
List<String> inputs = List.of("Alice", "  ", "Bo", "Charlie123", "@invalid");
inputs.stream()
     .filter(isValidUsername)
     .map(sanitize)
     .forEach(System.out::println);
// alice
// charlie123

// Best practice: name each processing step
Function<String, String> step1_trim = String::trim;
Function<String, String> step2_lower = String::toLowerCase;
Function<String, String[]> step3_split = s -> s.split(",");

// Composition reads in step order
Function<String, String> preprocess = step1_trim.andThen(step2_lower);

// Feed the result into a Stream
List<String> csvData = List.of(
    " Alice,Bob ",
    " Charlie,David "
);

csvData.stream()
    .map(preprocess)         // Trim & lowercase
    .map(step3_split)        // Split by comma
    .flatMap(Arrays::stream) // Flatten
    .forEach(System.out::println);
// alice
// bob
// charlie
// david

